SELECT preferred_size
FROM size_preferences
WHERE user_id = 1 AND garment_type_id = 1;

SELECT COUNT(image_id) AS total_images
FROM garment_images
WHERE garment_type_id = 1;

SELECT COUNT(DISTINCT preferred_size) AS unique_size_count
FROM size_preferences
WHERE garment_type_id = 1;

SELECT image_path
FROM garment_images
WHERE garment_type_id = 1 AND size = '24';

SELECT garment_type_id, MAX(upload_date) AS latest_upload_date
FROM garment_images
GROUP BY garment_type_id;
